#[repr(C)]
#[derive(Copy, Clone)]
pub struct inet_protosw {
    pub list: list_head,
    pub protocol: c_int,
    pub ops: *mut socket_ops,
    pub prot: *mut proto,
    pub flags: c_int,
}

#[repr(C)]
#[derive(Copy, Clone)]
pub struct socket {
