    disable_ipv6_mod == 0
}

#[unsafe(no_mangle)]
pub unsafe extern "C" fn inet6_sk_generic(sk: *mut sock) -> *mut ipv6_pinfo {
    if sk.is_null() {
        return ptr::null_mut();
    }

    let base = sk as *mut u8;
    let off = mem::size_of::<sock>() as isize;
    base.wrapping_offset(off) as *mut ipv6_pinfo
}

#[unsafe(no_mangle)]
pub unsafe extern "C" fn inet6_create(
    _net: *mut net,
    sock: *mut socket,
    protocol: c_int,
    _kern: c_int,
) -> c_int {
    if sock.is_null() {
        return EINVAL;
    }

    if protocol < 0 {
        return EINVAL;
    }

    let _ = &mut *sock;
    0
}

