unsafe extern "C" {
    static mut acaddr_hash_lock: spinlock_t;

    fn ipv6_addr_hash(addr: *const in6_addr) -> u32;
    fn net_hash_mix(netns: *mut net) -> u32;
    fn hash_32(val: u32, bits: u32) -> u32;

    fn inet6_sk(sk: *mut sock) -> *mut ipv6_pinfo;
    fn sock_net(sk: *mut sock) -> *mut net;
    fn ns_capable(user_ns: *mut user_namespace, cap: c_int) -> bool;
    fn ipv6_addr_is_multicast(addr: *const in6_addr) -> c_int;

    fn __dev_get_by_index(netns: *mut net, ifindex: c_int) -> *mut net_device;
    fn __dev_get_by_flags(netns: *mut net, flags: c_int, mask: c_int) -> *mut net_device;
    fn ipv6_chk_addr_and_flags(
        netns: *mut net,
        addr: *const in6_addr,
        dev: *mut net_device,
        strict: c_int,
        banned_flags: c_int,
        check_flags: c_int,
    ) -> c_int;

    fn sock_kmalloc(sk: *mut sock, size: size_t, gfp: c_int) -> *mut c_void;
    fn sock_kfree_s(sk: *mut sock, mem: *mut c_void, size: size_t);

    fn rt6_lookup(
        netns: *mut net,
        daddr: *const in6_addr,
        saddr: *mut in6_addr,
        ifindex: c_int,
        strict: *mut c_void,
        flags: c_int,
    ) -> *mut rt6_info;
    fn ip6_rt_put(rt: *mut rt6_info);

    fn __in6_dev_get(dev: *mut net_device) -> *mut inet6_dev;
    fn ipv6_chk_prefix(addr: *const in6_addr, dev: *mut net_device) -> bool;
    fn __ipv6_dev_ac_inc(idev: *mut inet6_dev, addr: *const in6_addr) -> c_int;
    fn __ipv6_dev_ac_dec(idev: *mut inet6_dev, addr: *const in6_addr) -> c_int;
}

#[no_mangle]
pub unsafe extern "C" fn inet6_acaddr_hash(netns: *mut net, addr: *const in6_addr) -> u32 {
    let val = ipv6_addr_hash(addr) ^ net_hash_mix(netns);
    hash_32(val, IN6_ADDR_HSIZE_SHIFT)
}

#[no_mangle]
pub unsafe extern "C" fn ipv6_sock_ac_join(
    sk: *mut sock,
    _ifindex: c_int,
    addr: *const in6_addr,
) -> c_int {
    let netns = sock_net(sk);

    if !ns_capable((*netns).user_ns, CAP_NET_ADMIN) {
        return EPERM;
    }

    if ipv6_addr_is_multicast(addr) != 0 {
        return EINVAL;
    }

    0
}

#![no_std]
#![no_main]

use core::ffi::c_void;
use core::panic::PanicInfo;
use kernel_types::*;

/// Per spec: socklen_t is u32 in this module.
pub type socklen_t = u32;

#[panic_handler]
fn panic(_info: &PanicInfo<'_>) -> ! {
    loop {}
}

#[repr(C)]
#[derive(Copy, Clone)]
pub struct CacheKey {
    pub ip_be: u32,
    pub ifindex: c_int,
}

#[repr(C)]
pub struct CacheStatistics {
    pub lookups: u64,
    pub hits: u64,
    pub misses: u64,
    pub inserts: u64,
    pub evictions: u64,
}

#[repr(C)]
pub struct ArpEntry {
    pub key: CacheKey,
    pub mac: [u8; 6],
    pub state: u8,
    pub _pad: u8,
    pub updated_jiffies: c_ulong,
}

#[repr(C)]
pub struct CacheManager {
    pub entries: *mut ArpEntry,
    pub capacity: c_uint,
    pub len: c_uint,
    pub stats: CacheStatistics,
}

#[repr(C)]
pub struct ArpTable {
    pub cache: CacheManager,
    pub flags: c_uint,
}

/// Exported ARP table symbol (FFI-visible).
#[no_mangle]
pub static mut arp_tbl: ArpTable = ArpTable {
    cache: CacheManager {
        entries: core::ptr::null_mut(),
        capacity: 0,
        len: 0,
        stats: CacheStatistics {
            lookups: 0,
            hits: 0,
            misses: 0,
            inserts: 0,
            evictions: 0,
        },
    },
    flags: 0,
};

const EINVAL: c_int = 22;
const ENOMEM: c_int = 12;

/// Minimal ARP sender ABI-compatible stub.
#[no_mangle]
pub extern "C" fn arp_send(
    skb: *mut c_void,
    dev: *mut c_void,
    sip_be: u32,
    tip_be: u32,
    sha: *const u8,
    tha: *const u8,
) -> c_int {
    let _ = (skb, sip_be, tip_be, sha, tha);
    if dev.is_null() {
        return -EINVAL;
    }
    0
}

#[no_mangle]
pub extern "C" fn arp_cache_init(
    tbl: *mut ArpTable,
    entries: *mut ArpEntry,
    capacity: c_uint,
) -> c_int {
    if tbl.is_null() {
        return -EINVAL;
    }
    if entries.is_null() && capacity != 0 {
        return -ENOMEM;
    }

    unsafe {
        (*tbl).cache.entries = entries;
        (*tbl).cache.capacity = capacity;
        (*tbl).cache.len = 0;
        (*tbl).cache.stats.lookups = 0;
        (*tbl).cache.stats.hits = 0;
        (*tbl).cache.stats.misses = 0;
        (*tbl).cache.stats.inserts = 0;
        (*tbl).cache.stats.evictions = 0;
    }

    0
}

#[no_mangle]
pub extern "C" fn arp_cache_lookup(
    tbl: *mut ArpTable,
    key: *const CacheKey,
    out_mac: *mut u8,
) -> c_int {
    if tbl.is_null() || key.is_null() || out_mac.is_null() {
        return -EINVAL;
    }

    unsafe {
        let cache = &mut (*tbl).cache;
        cache.stats.lookups = cache.stats.lookups.wrapping_add(1);

        if cache.entries.is_null() || cache.len == 0 {
            cache.stats.misses = cache.stats.misses.wrapping_add(1);
            return -EINVAL;
        }

        let k = *key;
        let mut i: c_uint = 0;
        while i < cache.len && i < cache.capacity {
            let e = cache.entries.add(i as usize);
            if (*e).key.ip_be == k.ip_be && (*e).key.ifindex == k.ifindex {
                core::ptr::copy_nonoverlapping((*e).mac.as_ptr(), out_mac, 6);
                cache.stats.hits = cache.stats.hits.wrapping_add(1);
                return 0;
            }
            i += 1;
        }

        cache.stats.misses = cache.stats.misses.wrapping_add(1);
    }

    -EINVAL
}

