    if entry.is_null() {
        return;
    }

    if !(*entry).lsm_data.is_null() {
        netlbl_secattr_cache_free((*entry).lsm_data);
    }

    if !(*entry).key.is_null() {
        kfree((*entry).key as *mut c_void);
    }

    kfree(entry as *mut c_void);
