pub extern "C" fn in_dev_get(dev: *mut net_device) -> *mut in_device {
    unsafe {
        if GLOBAL_IDEV.is_null() {
            return null_mut();
        }
        if (*GLOBAL_IDEV).dev == dev {
            (*GLOBAL_IDEV).refcnt += 1;
            GLOBAL_IDEV
        } else {
            null_mut()
        }
    }
}

#[no_mangle]
pub extern "C" fn in_dev_put(idev: *mut in_device) {
    if idev.is_null() {
