            SKB_GSO_UDP_TUNNEL_CSUM
        } else {
            SKB_GSO_UDP_TUNNEL
        };

        let err = __gue_build_header(skb, e, protocol, &mut sport, type_);
        if err != 0 {
            return err;
        }

        fou6_build_udp(skb, e, fl6, protocol, sport);
        0
    }
}

