    if net.is_null() {
        return ptr::null_mut();
    }

    let hash: usize = (id as usize) & (FIB6_TABLE_HASHSZ - 1);
    let mut node = (*net).ipv6.fib_table_hash[hash].first;

    while !node.is_null() {
        let tb = node as *mut fib6_table;
        if (*tb).tb6_id == id {
            return tb;
        }
        node = (*node).next;
    }

    ptr::null_mut()
}

