pub const ETH_P_IPV6: c_int = 0x86DD;

// Missing protocol/GSO constants
pub const IPPROTO_UDP: u8 = 17;
pub const SKB_GSO_IPXIP4: c_uint = 1 << 0;
pub const SKB_GSO_IPXIP6: c_uint = 1 << 1;
