#[no_mangle]
pub unsafe extern "C" fn get_len(bs: *mut bitstr) -> c_uint {
    let v = *(*bs).cur;
    (*bs).cur = (*bs).cur.add(1);

    if (v & 0x80) != 0 {
        let n = (v & 0x3f) as c_uint;
        (n << 8) | (*(*bs).cur as c_uint)
    } else {
        v as c_uint
    }
}

#[no_mangle]
pub unsafe extern "C" fn nf_h323_error_boundary(bs: *mut bitstr, bytes: size_t, bits: size_t) -> c_int {
    let total_bits = (*bs).bit as size_t + bits;
    let mut total_bytes = bytes + (total_bits / 8);
    if (total_bits % 8) != 0 {
        total_bytes += 1;
    }

    if (*bs).cur.add(total_bytes) > (*bs).end {
        H323_ERROR_BOUND
    } else {
        H323_ERROR_NONE
    }
}

#[no_mangle]
pub unsafe extern "C" fn get_bit(bs: *mut bitstr) -> c_uint {
    let b = *(*bs).cur & (0x80u8 >> (*bs).bit);

    (*bs).bit += 1;
    if (*bs).bit > 7 {
        (*bs).cur = (*bs).cur.add(1);
        (*bs).bit = 0;
    }

    b as c_uint
}

#[no_mangle]
pub unsafe extern "C" fn get_bits(bs: *mut bitstr, b: c_uint) -> c_uint {
    let mut v: c_uchar = *(*bs).cur & (0xffu8 >> (*bs).bit);
    let l = (*bs).bit + b;

    if l < 8 {
        v >>= 8 - l;
        (*bs).bit = l;
    } else if l == 8 {
        (*bs).cur = (*bs).cur.add(1);
        (*bs).bit = 0;
    } else {
        v <<= 8 - (*bs).bit;
        (*bs).cur = (*bs).cur.add(1);
        v |= *(*bs).cur;
        v >>= 16 - l;
        (*bs).bit = l - 8;
    }

    v as c_uint
}

#[no_mangle]
pub unsafe extern "C" fn get_bitmap(bs: *mut bitstr, b: c_uint) -> c_uint {
    if b == 0 {
        return 0;
    }

    let mut rem = b;
    let mut out: c_uint = 0;

    while rem != 0 {
        out <<= 1;
        out |= get_bit(bs) & 1;
        rem -= 1;
    }

    out
}

use kernel_types::*;
use core::ffi::{c_char, c_int, c_uint, c_void};
use core::ptr;

type ExpectFn = Option<extern "C" fn(*mut c_void, *mut c_void, *mut c_void) -> c_int>;
type gfp_t = c_uint;

unsafe extern "C" {
    fn kmalloc(size: usize, flags: gfp_t) -> *mut c_void;
    fn kfree(objp: *const c_void);
}

const GFP_KERNEL: gfp_t = 0x10u32;

#[repr(C)]
#[derive(Copy, Clone)]
pub struct h323_call_id {
    pub call_id: [c_char; 128],
    pub call_id_len: c_int,
}

#[repr(C)]
#[derive(Copy, Clone)]
pub struct h323_call_signal {
    pub call_id: h323_call_id,
    pub setup: u8,
    pub connect: u8,
    pub release_complete: u8,
    pub call_type: c_int,
}

#[repr(C)]
#[derive(Copy, Clone)]
pub struct h323_call {
    pub call_signal: h323_call_signal,
    pub src_addr: nf_inet_addr,
    pub dst_addr: nf_inet_addr,
    pub src_port: __be16,
    pub dst_port: __be16,
    pub protocol: c_int,
    pub af: c_int,
}

#[repr(C)]
#[derive(Copy, Clone)]
pub struct h323_expect {
    pub call: h323_call,
    pub timeout: c_uint,
    pub flags: c_uint,
    pub master: *mut c_void,
    pub expectfn: ExpectFn,
    pub expect_data: *mut c_void,
}

#[no_mangle]
pub extern "C" fn h323_expect_create(
    call: *mut h323_call,
    timeout: c_uint,
    flags: c_uint,
    master: *mut c_void,
    expectfn: ExpectFn,
    expect_data: *mut c_void,
) -> *mut h323_expect {
    if call.is_null() {
        return ptr::null_mut();
    }

    let expect = unsafe { kmalloc(core::mem::size_of::<h323_expect>(), GFP_KERNEL) as *mut h323_expect };
    if expect.is_null() {
        return ptr::null_mut();
    }

    unsafe {
        ptr::write(
            expect,
            h323_expect {
                call: *call,
                timeout,
                flags,
                master,
                expectfn,
                expect_data,
            },
        );
    }

    expect
}

#[no_mangle]
pub extern "C" fn h323_expect_destroy(expect: *mut h323_expect) {
    if !expect.is_null() {
        unsafe {
            ptr::drop_in_place(expect);
            kfree(expect as *const c_void);
        }
    }
}

#[no_mangle]
pub extern "C" fn h323_expect_match(expect: *mut h323_expect, call: *mut h323_call) -> bool {
    if expect.is_null() || call.is_null() {
        return false;
    }

    unsafe {
        let expect_call = &(*expect).call;
        let match_call = &*call;

        if expect_call.call_signal.call_id.call_id_len != match_call.call_signal.call_id.call_id_len {
            return false;
        }

        let len = expect_call.call_signal.call_id.call_id_len;
        if len < 0 || len as usize > expect_call.call_signal.call_id.call_id.len() {
            return false;
        }

        for i in 0..(len as usize) {
            if expect_call.call_signal.call_id.call_id[i] != match_call.call_signal.call_id.call_id[i] {
                return false;
            }
        }

        if expect_call.src_addr.all != match_call.src_addr.all {
            return false;
        }

        if expect_call.dst_addr.all != match_call.dst_addr.all {
            return false;
        }

        if expect_call.src_port != match_call.src_port {
            return false;
        }

        if expect_call.dst_port != match_call.dst_port {
            return false;
        }

        if expect_call.protocol != match_call.protocol {
            return false;
        }

        if expect_call.af != match_call.af {
            return false;
        }

        true
    }
}

#[no_mangle]
pub extern "C" fn h323_expect_attach(expect: *mut h323_expect, skb: *mut sk_buff) -> c_int {
    if expect.is_null() || skb.is_null() {
        return -1;
    }

    unsafe {
        match (*expect).expectfn {
            Some(expectfn) => expectfn((*expect).master, skb as *mut c_void, (*expect).expect_data),
            None => 0,
        }
    }
}

