pub const HZ: c_uint = 100;
pub const CTA_TIMEOUT_GENERIC_TIMEOUT: usize = 1;
pub const CTA_TIMEOUT_GENERIC_MAX: usize = 2;
pub const ENOSPC: c_int = -12;

pub const NLA_U32: c_uint = 1;
pub const IPPROTO_RAW: u8 = 255;

#[repr(C)]
#[derive(Copy, Clone)]
