}

// C struct translations
#[repr(C)]
#[derive(Copy, Clone)]
pub struct tcphdr {
    pub source: u16,
    pub dest: u16,
    pub doff: u8,
    pub _pad: [u8; 3],
}

#[repr(C)]
#[derive(Copy, Clone)]
pub struct sane_request {
    pub RPC_code: u32,
    pub handle: u32,
}

#[repr(C)]
#[derive(Copy, Clone)]
