#[no_mangle]
pub unsafe extern "C" fn callid_len(
    _ct: *const nf_conn,
    dptr: *const c_uchar,
    limit: *const c_uchar,
    shift: *mut c_int,
) -> c_int {
    let mut len = word_len(dptr, limit);
    let mut current = dptr.add(len as usize);

    if len == 0 || current >= limit || *current != b'@' {
        if !shift.is_null() {
            *shift = len;
        }
        return len;
    }

    current = current.add(1);
    len += 1;

    let domain_len = word_len(current, limit);
    if domain_len == 0 {
        if !shift.is_null() {
            *shift = 0;
        }
        return 0;
    }

    len += domain_len;
    if !shift.is_null() {
        *shift = len;
    }
    len
}

