static AMANDA_NAME: &[u8; 7] = b"amanda\0";
static ALL_PORTS_IN_USE: &[u8; 17] = b"all ports in use\0";
static CANNOT_MANGLE_PACKET: &[u8; 21] = b"cannot mangle packet\0";

static mut NAT_HELPER_AMANDA: nf_conntrack_nat_helper =
    nf_ct_nat_helper_init(AMANDA_NAME.as_ptr() as *const c_char);

#[unsafe(no_mangle)]
static mut nf_nat_amanda_hook: Option<
    unsafe extern "C" fn(
        skb: *mut sk_buff,
        ctinfo: c_uint,
        protoff: c_uint,
        matchoff: c_uint,
        matchlen: c_uint,
        exp: *mut nf_conntrack_expect,
    ) -> c_uint,
> = None;

#[unsafe(no_mangle)]
pub unsafe extern "C" fn help(
    skb: *mut sk_buff,
    ctinfo: c_uint,
    protoff: c_uint,
    matchoff: c_uint,
    matchlen: c_uint,
    exp: *mut nf_conntrack_expect,
) -> c_uint {
    if exp.is_null() {
        return NF_DROP;
    }

    unsafe {
        (*exp).saved_proto.tcp.port = (*exp).tuple.dst.u.tcp.port;
        (*exp).dir = IP_CT_DIR_ORIGINAL;
        (*exp).expectfn = None;
    }

    let mut port: u16 = unsafe { ntohs((*exp).saved_proto.tcp.port) };

    while port != 0 {
        unsafe {
            (*exp).tuple.dst.u.tcp.port = htons(port);
        }
        let res = unsafe { nf_ct_expect_related(exp, 0) };

        if res == 0 {
            break;
        } else if res != -EBUSY {
            port = 0;
            break;
        }

        port = port.wrapping_sub(1);
    }

    if port == 0 {
        unsafe {
            nf_ct_helper_log(
                skb,
                core::ptr::null_mut(),
                ALL_PORTS_IN_USE.as_ptr() as *const c_char,
            );
        }
        return NF_DROP;
    }

    let mut buffer: [u8; 6] = [0; 6];
    let mut temp = port;
    let mut i: usize = 5;
    buffer[i] = 0;

    if temp == 0 {
        i = 4;
        buffer[i] = b'0';
    } else {
        while temp > 0 && i > 0 {
            i -= 1;
            buffer[i] = b'0' + (temp % 10) as u8;
            temp /= 10;
        }
    }

    let buflen: c_uint = (5 - i) as c_uint;

    let rc = unsafe {
        nf_nat_mangle_udp_packet(
            skb,
            core::ptr::null_mut(),
            ctinfo,
            protoff,
            matchoff,
            matchlen,
            buffer[i..5].as_ptr(),
            buflen,
        )
    };

    if rc == 0 {
        unsafe {
            nf_ct_helper_log(
                skb,
                core::ptr::null_mut(),
                CANNOT_MANGLE_PACKET.as_ptr() as *const c_char,
            );
            nf_ct_unexpect_related(exp);
        }
        return NF_DROP;
    }

    NF_ACCEPT
}

