    let mode = (*tuninfo).mode;
    let mut head: size_t = 0;

    match mode {
        0 => {}
        1 => head = mem::size_of::<ipv6hdr>(),
        2 => return 0,
        _ => {}
    }

    let hdrlen = (*tuninfo)
        .srh
        .as_ref()
        .map_or(0, |srh| ((srh.hdrlen as size_t) + 1) << 3);

