    let srh = (skb_data(skb) as *mut u8).offset(srhoff as isize) as *mut ipv6_sr_hdr;

    let len = (((*srh).hdrlen as c_int) + 1) << 3;
    if !pskb_may_pull(skb, srhoff + len) {
