    let headp = proto_handlers(protocol);
    if headp.is_null() {
        return 0;
    }

    let mut handler = (*headp).load(Ordering::Acquire);
    while !handler.is_null() {
        let ret = ((*handler).cb_handler)(skb, err);
        if ret <= 0 {
            return ret;
        }
        handler = (*handler).next;
    }
    0
}

