// Constants from C
const XFRM6_TUNNEL_SPI_BYADDR_HSIZE: c_uint = 256;
const XFRM6_TUNNEL_SPI_BYSPI_HSIZE: c_uint = 256;
const XFRM6_TUNNEL_SPI_MIN: u32 = 1;
const XFRM6_TUNNEL_SPI_MAX: u32 = 0xFFFF_FFFF;

// Type definitions
#[repr(C)]
