        ttl: 64,
        protocol: 6,  // TCP
        check: 0,
        saddr: ipv4_addr.s_addr,
        daddr: u32::from_be_bytes([8, 8, 8, 8]),  // 8.8.8.8
    };

    // IPv6 header
